; [AI] SYNCHR -- Microsoft BASIC's "syntax-require" check. Called as
;        CALL SYNCHR  /  DEFB <expected-char>
;      Compares the current program byte (at HL) with the byte inlined right
;      after the CALL. If they differ -> "?SN Error" (ERR_19). If they match,
;      step past the inlined byte and advance to the next program char (falls
;      into the CHRGOT/CHRGET scanner). Pervasive in statement parsing.
SYNCHR:
        LD A,(HL)                        ; $45A3  7E   current text char
        EX (SP),HL                       ; $45A4  E3   HL -> inlined expected char
        CP (HL)                          ; $45A5  BE   match?
SYNCHR_1:
        JR NZ,SYNCHR_8                 ; $45A6  20 0A  no -> SN error
SYNCHR_2:
        INC HL                           ; $45A8  23   skip the inlined byte
SYNCHR_3:
        EX (SP),HL                       ; $45A9  E3   restore caller return addr
SYNCHR_4:
        INC HL                           ; $45AA  23   advance text pointer
